import torch
import triton
import triton.language as tl

def fused_hardsigmoid_batch_norm(x: torch.Tensor, running_mean: torch.Tensor, running_var: torch.Tensor, weight: torch.Tensor = None, bias: torch.Tensor = None, training: bool = False, momentum: float = 0.1, eps: float = 1e-5, inplace: bool = False) -> torch.Tensor:
    if training:
        return _fused_hardsigmoid_batch_norm_train(x, running_mean, running_var, weight, bias, momentum, eps)
    else:
        return _fused_hardsigmoid_batch_norm_inference(x, running_mean, running_var, weight, bias, eps, inplace)

def _fused_hardsigmoid_batch_norm_train(x, running_mean, running_var, weight, bias, momentum, eps):
    # Get input dimensions
    batch, channels, height, width = x.shape

    # Flatten for easier processing
    x_flat = x.view(batch * channels, height * width)

    # Allocate output tensor
    output = torch.empty_like(x_flat)

    # Compute batch mean and variance
    mean = x_flat.mean(dim=1, keepdim=True)
    var = x_flat.var(dim=1, keepdim=True, unbiased=False)

    # Update running statistics
    running_mean.copy_(momentum * mean.squeeze(1) + (1 - momentum) * running_mean)
    running_var.copy_(momentum * var.squeeze(1) + (1 - momentum) * running_var)

    # Normalize
    x_norm = (x_flat - mean) / (torch.sqrt(var + eps))

    # Apply weight and bias if provided
    if weight is not None and bias is not None:
        x_norm = x_norm * weight.view(1, -1) + bias.view(1, -1)

    # Apply hardsigmoid
    output = torch.clamp(x_norm * 0.2 + 0.5, 0, 1)

    return output.view(batch, channels, height, width)

def _fused_hardsigmoid_batch_norm_inference(x, running_mean, running_var, weight, bias, eps, inplace):
    # Get input dimensions
    batch, channels, height, width = x.shape

    # Flatten for easier processing
    x_flat = x.view(batch * channels, height * width)

    # Normalize using running statistics
    x_norm = (x_flat - running_mean.view(1, -1)) / (torch.sqrt(running_var.view(1, -1) + eps))

    # Apply weight and bias if provided
    if weight is not None and bias is not None:
        x_norm = x_norm * weight.view(1, -1) + bias.view(1,-1)

    # Apply hardsigmoid
    if inplace:
        x_flat = x_norm
        x_flat = torch.clamp(x_flat * 0.2 + 0.5, 0, 1)
        return x_flat.view(batch, channels, height, width)
    else:
        output = torch.clamp(x_norm * 0.2 + 0.5, 0, 1)
        return output.view(batch, channels, height, width)

import torch
import triton
import triton.language as tl

def sgd_kernel(
    param_ptr, grad_ptr, momentum_ptr, state_ptr,
    lr, momentum, weight_decay, dampening, nesterov, maximize,
    param_stride, grad_stride, momentum_stride, state_stride,
    n_elements, BLOCK_SIZE: int = 1024
):
    pid = tl.program_id(axis=0)
    block_start = pid * BLOCK_SIZE
    offsets = block_start + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements

    param = tl.load(param_ptr + offsets, mask=mask)
    grad = tl.load(grad_ptr + offsets, mask=mask)

    if weight_decay != 0:
        grad = grad + weight_decay * param

    if momentum != 0:
        momentum_val = tl.load(momentum_ptr + offsets, mask=mask)
        if dampening != 0:
            momentum_val = momentum_val * momentum + (1 - dampening) * grad
        else:
            momentum_val = momentum_val * momentum + grad

        if nesterov:
            grad = grad + momentum * momentum_val
        else:
            grad = momentum_val

        tl.store(momentum_ptr + offsets, momentum_val, mask=mask)

    if maximize:
        param = param - lr * grad
    else:
        param = param - lr * grad

    tl.store(param_ptr + offsets, param, mask=mask)

