import triton
import triton.language as tl

def fused_cholesky_solve(A: Tensor, b: Tensor) -> Tensor:
    return cholesky_solve_kernel(A, b)

@triton.jit
def cholesky_solve_kernel(A, b, output, n, k, BLOCK_SIZE: tl.constexpr):
    # Compute Cholesky decomposition
    L = tl.zeros((n, n), dtype=tl.float32)

    # Compute lower triangular matrix L
    for i in range(n):
        for j in range(i+1):
            if i == j:
                sum_val = 0.0
                for k_idx in range(j):
                    sum_val += L[i, k_idx] * L[i, k_idx]
                L[i, j] = tl.sqrt(A[i, j] - sum_val)
            else:
                sum_val = 0.0
                for k_idx in range(j):
                    sum_val += L[i, k_idx] * L[j, k_idx]
                L[i, j] = (A[i, j] - sum_val) / L[j, j]

    # Forward substitution to solve L * y = b
    y = tl.zeros((n, k), dtype=tl.float32)
    for i in range(n):
        sum_val = 0.0
        for j in range(i):
            sum_val += L[i, j] * y[j, 0]
        y[i, 0] = (b[i, 0] - sum_val) / L[i, i]

    # Backward substitution to solve L.T * x = y
    for i in range(n-1, -1, -1):
        sum_val = 0.0
        for j in range(i+1, n):
            sum_val += L[j, i] * output[j, 0]
        output[i, 0] = (y[i, 0] - sum_val) / L[i, i]

    # Copy result to output tensor
    for i in range(n):
        for j in range(k):
            output[i, j] = output[i, j]

