def addmm_triton(input, mat1, mat2, *, beta=1, alpha=1, out=None):
    # Ensure inputs are on the same device
    if input.device != mat1.device or input.device != mat2.device:
        raise ValueError("All tensors must be on the same device")

    # Get dimensions
    n, m = mat1.shape
    m2, p = mat2.shape

    # Check dimensions
    if m != m2:
        raise ValueError("Matrix dimensions incompatible for multiplication")

    # Check if input is broadcastable with output
    if input.shape != (n, p) and input.shape != (1, p) and input.shape != (n, 1):
        raise ValueError("Input tensor is not broadcastable with output")

    # Create output tensor if not provided
    if out is None:
        out = torch.empty(n, p, device=input.device, dtype=input.dtype)
    else:
        if out.shape != (n, p):
            raise ValueError("Output tensor must have shape (n, p)")

    # Handle case where beta is 0
    if beta == 0:
        # Only compute alpha * (mat1 @ mat2)
        if alpha == 1:
            out.copy_(torch.mm(mat1, mat2))
        else:
            out.copy_(alpha * torch.mm(mat1, mat2))
        return out

    # For non-zero beta, compute alpha * (mat1 @ mat2) + beta * input
    if alpha == 1 and beta == 1:
        out.copy_(torch.mm(mat1, mat2) + input)
    elif alpha == 1:
        out.copy_(torch.mm(mat1, mat2) + beta * input)
    elif beta == 1:
        out.copy_(alpha * torch.mm(mat1, mat2) + input)
    else:
        out.copy_(alpha * torch.mm(mat1, mat2) + beta * input)

    return out

