import triton.language as tl

@triton.jit
def trunc_kernel(x_ptr, output_ptr, n_elements, BLOCK_SIZE: int = 1024):
    pid = tl.program_id(0)
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements
    x = tl.load(x_ptr + offsets, mask=mask)
    output = tl.math.trunc(x)
    tl.store(output_ptr + offsets, output, mask=mask)


def trunc(input, *, out=None):
    if out is None:
        out = input
    else:
        if input.dtype != out.dtype:
            raise ValueError("Input and output tensors must have the same dtype.")

    n_elements = input.numel()
    grid = (triton.cdiv(n_elements, 1024),)

    if input.dtype in [tl.float32, tl.float64]:
        trunc_kernel[grid](input.data_ptr(), out.data_ptr(), n_elements)
    else:
        # For integer types, copy the input to output
        tl.copy(input.data_ptr(), out.data_ptr(), n_elements)

    return out

