def gelu_std(input, dim=None, keepdim=False, correction=1, approximate='none', out=None) -> torch.Tensor:
    """Computes GELU activation followed by standard deviation along specified dimensions."""
    # Handle input tensor
    input = input.contiguous()

    # Determine output shape
    if dim is None:
        output_shape = []
    else:
        if isinstance(dim, int):
            dims = [dim]
        else:
            dims = list(dim)

        # Normalize negative dimensions
        normalized_dims = []
        for d in dims:
            if d < 0:
                normalized_dims.append(d + input.dim())
            else:
                normalized_dims.append(d)

        # Create output shape
        output_shape = list(input.shape)
        for d in sorted(normalized_dims, reverse=True):
            if keepdim:
                output_shape[d] = 1
            else:
                output_shape.pop(d)

    # Create output tensor
    if out is None:
        out = torch.empty(output_shape, dtype=torch.float32, device=input.device)
    else:
        assert out.shape == tuple(output_shape), "Output tensor shape mismatch"

    # Get the appropriate kernel
    if approximate == 'none':
        kernel = _gelu_std_kernel
    else:
        kernel = _gelu_std_kernel_approx

    # Launch kernel
    grid = (triton.cdiv(input.numel(), 1024), 1, 1)
    kernel[grid](input, out, input.numel(), correction, keepdim, dim)

    return out

@triton.jit
def _gelu_std_kernel(input_ptr, output_ptr, n_elements, correction, keepdim, dim):
    # Get block size
    BLOCK_SIZE = 1024

    # Get thread index
    pid = tl.program_id(0)

    # Calculate offsets
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)

    # Load input data
    mask = offsets < n_elements
    input = tl.load(input_ptr + offsets, mask=mask)

    # Apply GELU activation
    output = _gelu_activation(input)

    # Store output
    tl.store(output_ptr + offsets, output, mask=mask)

@triton.jit
def _gelu_std_kernel_approx(input_ptr, output_ptr, n_elements, correction, keepdim, dim):
    # Get block size
    BLOCK_SIZE = 1024

    # Get thread index
    pid = tl.program_id(0)

    # Calculate offsets
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)

    # Load input data
    mask = offsets < n_elements
    input = tl.load(input_ptr + offsets, mask=mask)

    # Apply approximate GELU activation
    output = _gelu_activation_approx(input)

    # Store output
    tl.store(output_ptr + offsets, output, mask=mask)

@triton.jit
def _gelu_activation(x):
    # Standard GELU implementation
    return 0.5 * x * (1 + tl.tanh(0.7978845608 * (x + 0.044715 * x * x * x)))

@triton.jit
def _gelu_activation_approx(x):
    # Approximate GELU implementation
    return 0.5 * x * (1 + tl.tanh(x * 0.7978845608))

